// Buffalo Cubic: z_{n+1} = |Re(z^3)| + i|Im(z^3)| + c
// Extends Buffalo to power 3 — abs applied to BOTH Re and Im of z^3.
// The 3-fold symmetry produces richer branching than the quadratic Buffalo.
// Supports normal-map shading (colorScheme 50-63).
uniform float uTime;          // 0
uniform vec2  uResolution;    // 1-2
uniform vec2  uCenter;        // 3-4
uniform float uZoom;          // 5
