--- shaders/escape_time_family/families/buffalo/buffalo_cubic_julia_gpu.frag
#include <flutter/runtime_effect.glsl>

precision highp float;

// Buffalo cubic Julia: z_{n+1} = |Re(z^3)| + i|Im(z^3)| + c, c = (−0.35, 0.55).
// Julia set of the cubic Buffalo map — pixel = z₀, c = (−0.35, 0.55).
// Buffalo folds both real and imaginary parts of z^3 through absolute
// value before adding c, producing four-fold (quadrant) reflection
// symmetry. The cubic degree adds an extra arm compared to Buffalo²,
// yielding a three-armed body with 12-fold total decorations after
// unfolding. Near c=(−0.35, 0.55) the Julia set forms an intricate
// lace pattern with tight spiral arms at each fold boundary.
// Derivative approximation: 3z²·der (abs ignored for normal map).
// Supports normal-map shading (colorScheme 50-63).
uniform float uTime;
uniform vec2  uResolution;
uniform vec2  uCenter;
uniform float uZoom;
uniform float uIterations;
uniform float uBailout;
--- shaders/escape_time_family/families/buffalo/buffalo_gpu.frag
#include <flutter/runtime_effect.glsl>

precision highp float;

uniform float uTime;          // 0
uniform vec2  uResolution;    // 1-2
uniform vec2  uCenter;        // 3-4
uniform float uZoom;          // 5
uniform float uIterations;    // 6
uniform float uBailout;       // 7
uniform float uColorScheme;   // 8
uniform float uTransparentBg; // 9

out vec4 fragColor;

// IEC 61966-2-1 sRGB transfer function (linear → display-encoded).
vec3 linearToSRGB(vec3 lin) {
  lin = clamp(lin, 0.0, 1.0);
  bvec3 cutoff = lessThan(lin, vec3(0.0031308));
  vec3 hi = 1.055 * pow(max(lin, vec3(0.0031308)), vec3(1.0 / 2.4)) - 0.055;
