--- shaders/escape_time_family/families/buffalo/buffalo_power4_gpu.frag
#include <flutter/runtime_effect.glsl>

precision highp float;

// Buffalo degree 4: z_{n+1} = |Re(z^4)| + i|Im(z^4)| + c.
// First computes z^4 normally, then applies absolute values to both
// components before adding c. The absolute-value fold after squaring
// (rather than before, as in Burning Ship) creates an asymmetric
// reflection that produces the characteristic "buffalo horn" structures.
// Degree 4 extends the classic Buffalo (degree 2) with two additional
// fold symmetries and finer internal spiral detail.
// Supports normal-map shading (colorScheme 50-63).
uniform float uTime;
uniform vec2  uResolution;
uniform vec2  uCenter;
uniform float uZoom;
uniform float uIterations;
uniform float uBailout;
uniform float uColorScheme;
uniform float uTransparentBg;
--- shaders/escape_time_family/families/buffalo/buffalo_power4_julia_gpu.frag
#include <flutter/runtime_effect.glsl>

precision highp float;

// Buffalo⁴ Julia set: z_{n+1} = |Re(z⁴)| + i|Im(z⁴)| + c, c = (−0.40, 0.55).
// Julia set of the degree-4 Buffalo map — pixel = z₀, c = (−0.40, 0.55) is fixed.
// The Buffalo map raises z to the fourth power then folds both components through
// absolute value, producing four-fold symmetric Julia sets with crescent-shaped
// lobes and intricately folded boundary filaments. Near c=(−0.40, 0.55) the set
// is connected with visible fourfold structure and rich secondary detail.
// Derivative approximation: 4·z³·der (ignores abs fold at output).
// Supports normal-map shading (colorScheme 50-63).
uniform float uTime;
uniform vec2  uResolution;
uniform vec2  uCenter;
uniform float uZoom;
uniform float uIterations;
uniform float uBailout;
uniform float uColorScheme;
uniform float uTransparentBg;
--- shaders/escape_time_family/families/buffalo/buffalo_power5_gpu.frag
#include <flutter/runtime_effect.glsl>

precision highp float;

// Buffalo degree 5: z_{n+1} = |Re(z^5)| + i|Im(z^5)| + c.
// Extends the Buffalo fractal family to degree 5 by folding both real
// and imaginary parts of z^5 through absolute value. The four-fold
// quadrant symmetry of the Buffalo fold combined with the degree-5
// rotation structure gives 4-fold outer symmetry with internal 5-fold
// decoration — yielding 20 repeated sub-structures around the boundary.
// Derivative approximation: 5z^4·der + 1 (abs folds ignored).
// Supports normal-map shading (colorScheme 50-63).
uniform float uTime;
uniform vec2  uResolution;
uniform vec2  uCenter;
uniform float uZoom;
uniform float uIterations;
uniform float uBailout;
uniform float uColorScheme;
uniform float uTransparentBg;
