#include <flutter/runtime_effect.glsl>

precision highp float;

// Buffalo⁵ Julia set: z_{n+1} = |Re(z⁵)| + i|Im(z⁵)| + c, c = (−0.36, 0.52).
// Julia set of the degree-5 Buffalo map — pixel = z₀, c = (−0.36, 0.52) is fixed.
// The Buffalo map raises z to the fifth power then folds both real and imaginary
// components through absolute value. At degree 5 this produces five-fold symmetric
// Julia sets with crescent-shaped doubled lobes on all five arms — a fully
// symmetric version of the Celtic family. Near c=(−0.36, 0.52) the set is
// connected with five distinct primary lobes and intricate tertiary structures.
// Derivative approximation: 5z⁴·der (Julia mode, ignores abs fold at output).
// Supports normal-map shading (colorScheme 50-63).
uniform float uTime;
uniform vec2  uResolution;
uniform vec2  uCenter;
uniform float uZoom;
uniform float uIterations;
uniform float uBailout;
uniform float uColorScheme;
